def next_permutation(xs):
    n = len(xs)
    i = n - 2
    while i >= 0 and xs[i] >= xs[i + 1]:
        i -= 1
    if i == -1:
        xs.reverse()
    else:
        j = n - 1
        while xs[j] <= xs[i]:
            j -= 1
        xs[i], xs[j] = xs[j], xs[i]
        xs[i + 1:] = reversed(xs[i + 1:])
